import React from "react";

function Navbar() {
  return (
    <nav className="flex justify-between items-center px-10 py-5 text-white 
    backdrop-blur-md bg-white/5 border-b border-white/10">

      <h1 className="text-2xl font-bold tracking-wider text-blue-300">
        HIRETRAX
      </h1>

      <ul className="flex gap-8 text-sm">
        <li className="hover:text-blue-300 cursor-pointer">Home</li>
        <li className="hover:text-blue-300 cursor-pointer">Features</li>
        <li className="hover:text-blue-300 cursor-pointer">About</li>
        <li className="hover:text-blue-300 cursor-pointer">Contact</li>
      </ul>

      <button className="bg-blue-500 px-5 py-2 rounded-full hover:bg-blue-600 transition">
        Get Started
      </button>

    </nav>
  );
}

export default Navbar;
